import React from 'react';
import { SearchResults } from './SearchResults';
import './styles.css';

export default function App() {
  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif', maxWidth: '32rem' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>Live Region Search</h1>
      <SearchResults />
    </div>
  );
}

import React, { useState, useCallback } from 'react';
import './styles.css';

const ALL_ITEMS = [
  'React Hooks', 'Redux Toolkit', 'TypeScript Generics', 'CSS Grid',
  'Flexbox Layout', 'Accessibility', 'Web Components', 'React Router',
  'Next.js SSR', 'Vite Build Tool', 'Testing Library', 'Node.js',
];

export const SearchResults: React.FC = () => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [searched, setSearched] = useState(false);

  const handleSearch = useCallback(() => {
    if (!query.trim()) return;
    setLoading(true);
    setError('');
    setSearched(true);
    // Simulate async search
    setTimeout(() => {
      if (query.toLowerCase() === 'error') {
        setError('Search failed. Please try again.');
        setResults([]);
        setLoading(false);
        return;
      }
      const filtered = ALL_ITEMS.filter(item =>
        item.toLowerCase().includes(query.toLowerCase())
      );
      setResults(filtered);
      setLoading(false);
    }, 800);
  }, [query]);

  // TODO: Implement the component with proper ARIA live regions
  // 1. A visually-hidden status region (aria-live="polite") that announces result count
  // 2. An error region (role="alert") that announces errors
  // 3. aria-busy on results container during loading
  // 4. Loading indicator with role="status"

  return (
    <div>
      <div className="search-bar">
        <input
          data-testid="search-input"
          className="search-input"
          value={query}
          onChange={e => setQuery(e.target.value)}
          onKeyDown={e => e.key === 'Enter' && handleSearch()}
          placeholder="Search topics…"
        />
        <button data-testid="search-btn" className="search-btn" onClick={handleSearch}>
          Search
        </button>
      </div>

      {/* TODO: Add visually-hidden status live region */}
      <div data-testid="status-region">
        {/* This should announce result count to screen readers */}
      </div>

      {/* TODO: Add error live region */}
      <div data-testid="error-region">
        {error}
      </div>

      {loading && (
        <div data-testid="loading" className="search-loading">
          Searching…
        </div>
      )}

      <div data-testid="results" className="search-results">
        {results.map((item, i) => (
          <div key={item} data-testid={`result-${i}`} className="search-result">
            {item}
          </div>
        ))}
        {searched && !loading && results.length === 0 && !error && (
          <p className="search-empty">No results found</p>
        )}
      </div>
    </div>
  );
};

.search-bar {
  display: flex;
  gap: 0.5rem;
  margin-bottom: 1rem;
}

.search-input {
  flex: 1;
  padding: 0.5rem 0.75rem;
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  font-size: 0.875rem;
}

.search-input:focus {
  outline: 2px solid #3b82f6;
  outline-offset: 1px;
  border-color: #3b82f6;
}

.search-btn {
  padding: 0.5rem 1.25rem;
  background: #3b82f6;
  color: white;
  border: none;
  border-radius: 0.375rem;
  cursor: pointer;
  font-size: 0.875rem;
  font-weight: 500;
}

.search-btn:hover {
  background: #2563eb;
}

.search-loading {
  padding: 0.75rem;
  color: #3b82f6;
  font-size: 0.875rem;
}

.search-results {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.search-result {
  padding: 0.75rem 1rem;
  border: 1px solid #e5e7eb;
  border-radius: 0.375rem;
  font-size: 0.875rem;
}

.search-empty {
  color: #6b7280;
  font-size: 0.875rem;
  padding: 1rem 0;
}

.search-error {
  padding: 0.75rem 1rem;
  background: #fef2f2;
  border: 1px solid #fecaca;
  border-radius: 0.375rem;
  color: #991b1b;
  font-size: 0.875rem;
  margin-bottom: 0.75rem;
}

.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

