import { render, screen, fireEvent, act } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import App from './App';

describe('ARIA Live Regions', () => {
  beforeEach(() => {
    jest.useFakeTimers();
  });
  afterEach(() => {
    jest.useRealTimers();
  });

  it('status region has aria-live attribute', () => {
    render(<App />);
    const status = screen.getByTestId('status-region');
    expect(status).toHaveAttribute('aria-live', 'polite');
  });

  it('error region has role=alert', () => {
    render(<App />);
    const error = screen.getByTestId('error-region');
    expect(error).toHaveAttribute('role', 'alert');
  });

  it('shows loading indicator during search', () => {
    render(<App />);
    fireEvent.change(screen.getByTestId('search-input'), { target: { value: 'react' } });
    fireEvent.click(screen.getByTestId('search-btn'));
    expect(screen.getByTestId('loading')).toBeInTheDocument();
  });

  it('results container has aria-busy during loading', () => {
    render(<App />);
    fireEvent.change(screen.getByTestId('search-input'), { target: { value: 'react' } });
    fireEvent.click(screen.getByTestId('search-btn'));
    expect(screen.getByTestId('results')).toHaveAttribute('aria-busy', 'true');
  });

  it('updates status region with result count after search', () => {
    render(<App />);
    fireEvent.change(screen.getByTestId('search-input'), { target: { value: 'react' } });
    fireEvent.click(screen.getByTestId('search-btn'));
    act(() => { jest.advanceTimersByTime(800); });
    const status = screen.getByTestId('status-region');
    expect(status.textContent).toMatch(/\d+/);
  });

  it('shows error in error region', () => {
    render(<App />);
    fireEvent.change(screen.getByTestId('search-input'), { target: { value: 'error' } });
    fireEvent.click(screen.getByTestId('search-btn'));
    act(() => { jest.advanceTimersByTime(800); });
    const errorRegion = screen.getByTestId('error-region');
    expect(errorRegion.textContent).toBeTruthy();
  });

  it('loading indicator has role=status', () => {
    render(<App />);
    fireEvent.change(screen.getByTestId('search-input'), { target: { value: 'test' } });
    fireEvent.click(screen.getByTestId('search-btn'));
    expect(screen.getByTestId('loading')).toHaveAttribute('role', 'status');
  });
});

