import React, { useState, useCallback } from 'react';
import './styles.css';

const ALL_ITEMS = [
  'React Hooks', 'Redux Toolkit', 'TypeScript Generics', 'CSS Grid',
  'Flexbox Layout', 'Accessibility', 'Web Components', 'React Router',
  'Next.js SSR', 'Vite Build Tool', 'Testing Library', 'Node.js',
];

export const SearchResults: React.FC = () => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [searched, setSearched] = useState(false);
  const [statusMessage, setStatusMessage] = useState('');

  const handleSearch = useCallback(() => {
    if (!query.trim()) return;
    setLoading(true);
    setError('');
    setSearched(true);
    setStatusMessage('');
    setTimeout(() => {
      if (query.toLowerCase() === 'error') {
        setError('Search failed. Please try again.');
        setResults([]);
        setLoading(false);
        return;
      }
      const filtered = ALL_ITEMS.filter(item =>
        item.toLowerCase().includes(query.toLowerCase())
      );
      setResults(filtered);
      setStatusMessage(`${filtered.length} result${filtered.length !== 1 ? 's' : ''} found`);
      setLoading(false);
    }, 800);
  }, [query]);

  return (
    <div>
      <div className="search-bar">
        <input
          data-testid="search-input"
          className="search-input"
          value={query}
          onChange={e => setQuery(e.target.value)}
          onKeyDown={e => e.key === 'Enter' && handleSearch()}
          placeholder="Search topics…"
          aria-label="Search topics"
        />
        <button data-testid="search-btn" className="search-btn" onClick={handleSearch}>
          Search
        </button>
      </div>

      <div data-testid="status-region" aria-live="polite" className="sr-only">
        {statusMessage}
      </div>

      <div data-testid="error-region" role="alert">
        {error && <div className="search-error">{error}</div>}
      </div>

      {loading && (
        <div data-testid="loading" className="search-loading" role="status" aria-live="assertive">
          Searching…
        </div>
      )}

      <div data-testid="results" className="search-results" aria-busy={loading}>
        {results.map((item, i) => (
          <div key={item} data-testid={`result-${i}`} className="search-result">
            {item}
          </div>
        ))}
        {searched && !loading && results.length === 0 && !error && (
          <p className="search-empty">No results found</p>
        )}
      </div>
    </div>
  );
};
